<template>
        <van-search
                v-model="searchValue"
                show-action
                placeholder="请输入搜索关键词"
                @search="onSearch">
                <template #action>
                        <div @click="onCancel">取消</div>
                </template>
        </van-search>
        <van-cell v-for="item in items" :key="item" :title="item.name" @click=" clickItem(item) " />
</template>

<script>
import { ref } from 'vue'
export default {
    setup() {
        const searchValue = ref('')
        const items = ref([])
        return {
            searchValue,
            items
        }
    },
    name: 'Search',
    methods: {
        async onSearch() {
            alert(123)
            const res = await this.Ajax(this.$route.params.type === '6' ? 'srarchHci' : 'srarchDept', 'post', null, {
                name: this.searchValue
            })
            this.items = res.data
        },
        async onCancel() {
            alert(456)
            this.$router.go(-1)
        },
        clickItem(item) {
            this.$route.params.type === '6' ? this.$store.commit('questionSearch/sethocName', item) : this.$store.commit('questionSearch/setdeptName', item)
            this.$router.go(-1)
        }
    }
}
</script>

